  ('diplomatic-9e854390-moex-00008', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-114-06c9aafe', 'sub-diplomatic-9e854390-01', NULL, 'single_choice', '下列關於美國學者奈伊（JosephNye）所提出的軟實力（softpower）概念的說明，何者最正確？', '["軟實力是一種非脅迫的吸引力", "美國軟實力的核心是其強大的經濟實力與科技創新能力", "軟實力是一個規範性概念，不可被用於如希特勒或史達林等邪惡的目的", "軟實力與現實主義的理論相矛盾，是一種理想主義或自由主義的形式"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:28+00:00", "source_pdf_sha1": "21b6efc20e66", "answer_pdf_sha1": "e2f5813b191a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "201", "s": "0505", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際關係與國際現勢", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
